// ─── 검색 헬퍼 ───

/** 대학+학과로 커트라인 검색 */
export const findCutoffData = (
  university: string,
  department: string,
  admissionType?: "학종" | "교과"
): AdmissionCutoffEntry[] => {
  const uniNorm = university.replace(/대학교$/, "").trim();
  const deptNorm = department.replace(/[과부학]$/, "").trim();
  return ADMISSION_CUTOFF_DATA.filter((e) => {
    const eUni = e.university.replace(/대학교$/, "").trim();
    const eDept = e.department.replace(/[과부학]$/, "").trim();
    const uniMatch = eUni === uniNorm || e.university === university;
    const deptMatch =
      eDept === deptNorm ||
      e.department === department ||
      eDept.includes(deptNorm) ||
      deptNorm.includes(eDept);
    const typeMatch = !admissionType || e.admissionType === admissionType;
    return uniMatch && deptMatch && typeMatch;
  });
};
